easy.solution:
// TypeScript implementation for TS Access Modifiers
interface TSAccessModifiersPayload {
  id: number;
  title: string;
  status: 'active' | 'pending';
}

function processTSAccessModifiers(item: TSAccessModifiersPayload): string {
  return `[${item.id}] ${item.title}: ${item.status}`;
}

console.log(processTSAccessModifiers({ id: 1, title: 'TS Access Modifiers', status: 'active' }));

